SELECT o.*, s.name as showName, t.name as ticketName, u.username as userName FROM biz_order o LEFT JOIN biz_show s ON o.show_id = s.id LEFT JOIN biz_ticket t ON o.ticket_id = t.id LEFT JOIN sys_user u ON o.user_id = u.id WHERE o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.pay_time DESC, o.create_time DESC

